        .domain-display {
            font-size: 2.2em;
            font-weight: bold;
            margin: 20px 0;
            color: #fff;
            text-shadow: 1px 1px 3px rgba(0,0,0,0.3);
        }
        .sale-box {
            background: white;
            border-radius: 5px;
            box-shadow: 0 3px 10px rgba(0,0,0,0.1);
            padding: 30px;
            margin-bottom: 30px;
        }
        .price {
            color: #e74c3c;
            font-size: 1.8em;
            font-weight: bold;
            margin: 15px 0;
        }
        .contact-btn {
            display: inline-block;
            background: var(--primary-color);
            color: white;
            padding: 12px 30px;
            text-decoration: none;
            border-radius: 5px;
            font-weight: bold;
            transition: all 0.3s;
            border: none;
            cursor: pointer;
            font-size: 1.1em;
        }
        .contact-btn:hover {
            background: var(--secondary-color);
            transform: translateY(-2px);
            box-shadow: 0 5px 15px rgba(0,0,0,0.1);
        }
        .features {
            display: flex;
            flex-wrap: wrap;
            gap: 20px;
            margin: 30px 0;
        }
        .feature {
            flex: 1;
            min-width: 250px;
            background: white;
            padding: 20px;
            border-radius: 5px;
            box-shadow: 0 3px 10px rgba(0,0,0,0.1);
        }
        .feature h3 {
            color: var(--primary-color);
            margin-top: 0;
        }
        footer {
            text-align: center;
            padding: 20px 0;
            background: #333;
            color: #fff;
            margin-top: 50px;
        }
        .links-section {
            margin: 40px 0;
            padding: 20px;
            background: white;
            border-radius: 5px;
            box-shadow: 0 3px 10px rgba(0,0,0,0.1);
        }
        .links-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
            gap: 15px;
            margin-top: 20px;
        }
        .links-grid a {
            color: var(--primary-color);
            text-decoration: none;
            transition: all 0.2s;
            padding: 5px 0;
        }
        .links-grid a:hover {
            color: var(--secondary-color);
            text-decoration: underline;
            padding-left: 5px;
        }
        @media (max-width: 768px) {
            .domain-display {
                font-size: 1.8em;
            }
            h1 {
                font-size: 2em;
            }
        }
    </style>
</head>
